// The synthetic det-fn ensures has the shape
//     ({ A_post1 && A_post2 }) ==> det_remove_l3_entry_equal(r1, r2, post1_self_, post2_self_)
// so the per-run ensures conjuncts (e.g. `r1.0 == target_l2_p`) are NOT free
// hypotheses at the top of the proof body — that is exactly what made the
// previous attempt's first line
//     assert(r1.0 == target_l2_p);
// fail. Those facts only hold inside the antecedent of the implication.
//
// Repair: open `if (full_antecedent) { ... }`. Inside the branch every
// ensures conjunct of both runs is a hypothesis, so we can re-state and
// chain the per-field equalities (kernel_l4_end, page_closure().remove(...),
// mapping_2m / mapping_4k / mapping_1g, kernel_entries, plus the tuple-
// return components r.0, r.1@.is_init() / .addr()) through pre_self_ /
// target_l2_p to align triggers across the two runs. Outside the branch
// the implication is vacuous, so Verus discharges the ensures either way.
//
// Reveal the wf-equivalence broadcast lemmas the original function uses,
// so the post*_self_.wf() conjuncts in the antecedent unfold cleanly while
// z3 chains the page_closure / mapping_* equalities.
broadcast use PageTable::reveal_page_table_wf;
broadcast use PageTable::reveal_page_table_levels_wf;
broadcast use PageTable::reveal_page_table_disjoint_wf;
broadcast use PageTable::reveal_page_table_mappings_wf;
broadcast use PageTable::reveal_page_table_addtional_wf;

if ({
    &&& (post1_self_.wf())
    &&& (post1_self_.kernel_l4_end == pre_self_.kernel_l4_end)
    &&& (post1_self_.page_closure() =~= pre_self_.page_closure().remove(target_l2_p))
    &&& (post1_self_.mapping_2m() == pre_self_.mapping_2m())
    &&& (post1_self_.mapping_4k() =~= pre_self_.mapping_4k())
    &&& (post1_self_.mapping_1g() =~= pre_self_.mapping_1g())
    &&& (post1_self_.kernel_entries =~= pre_self_.kernel_entries)
    &&& (r1.0 == target_l2_p)
    &&& (r1.1@.is_init())
    &&& (r1.1@.addr() == target_l2_p)
    &&& (post2_self_.wf())
    &&& (post2_self_.kernel_l4_end == pre_self_.kernel_l4_end)
    &&& (post2_self_.page_closure() =~= pre_self_.page_closure().remove(target_l2_p))
    &&& (post2_self_.mapping_2m() == pre_self_.mapping_2m())
    &&& (post2_self_.mapping_4k() =~= pre_self_.mapping_4k())
    &&& (post2_self_.mapping_1g() =~= pre_self_.mapping_1g())
    &&& (post2_self_.kernel_entries =~= pre_self_.kernel_entries)
    &&& (r2.0 == target_l2_p)
    &&& (r2.1@.is_init())
    &&& (r2.1@.addr() == target_l2_p)
}) {
    // Tuple component .0: both runs pinned to `target_l2_p`.
    assert(r1.0 == target_l2_p);
    assert(r2.0 == target_l2_p);
    assert(r1.0 == r2.0);

    // Tuple component .1 — `is_init()`: both pinned to true.
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.is_init() == r2.1@.is_init());

    // Tuple component .1 — `addr()`: both pinned to `target_l2_p`.
    assert(r1.1@.addr() == target_l2_p);
    assert(r2.1@.addr() == target_l2_p);
    assert(r1.1@.addr() == r2.1@.addr());

    // kernel_l4_end: both pinned to pre_self_.kernel_l4_end.
    assert(post1_self_.kernel_l4_end == pre_self_.kernel_l4_end);
    assert(post2_self_.kernel_l4_end == pre_self_.kernel_l4_end);
    assert(post1_self_.kernel_l4_end == post2_self_.kernel_l4_end);

    // page_closure(): both pinned (extensional) to pre_self_.page_closure().remove(target_l2_p).
    assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(target_l2_p));
    assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(target_l2_p));
    assert(post1_self_.page_closure() =~= post2_self_.page_closure());
    assert(post1_self_.page_closure() == post2_self_.page_closure());

    // mapping_2m(): both pinned (==) to pre_self_.mapping_2m().
    assert(post1_self_.mapping_2m() == pre_self_.mapping_2m());
    assert(post2_self_.mapping_2m() == pre_self_.mapping_2m());
    assert(post1_self_.mapping_2m() == post2_self_.mapping_2m());
    assert(post1_self_.mapping_2m@ =~= post2_self_.mapping_2m@);
    assert(post1_self_.mapping_2m@ == post2_self_.mapping_2m@);

    // mapping_4k(): both pinned (extensional) to pre_self_.mapping_4k().
    assert(post1_self_.mapping_4k() =~= pre_self_.mapping_4k());
    assert(post2_self_.mapping_4k() =~= pre_self_.mapping_4k());
    assert(post1_self_.mapping_4k() =~= post2_self_.mapping_4k());
    assert(post1_self_.mapping_4k@ =~= post2_self_.mapping_4k@);
    assert(post1_self_.mapping_4k@ == post2_self_.mapping_4k@);

    // mapping_1g(): both pinned (extensional) to pre_self_.mapping_1g().
    assert(post1_self_.mapping_1g() =~= pre_self_.mapping_1g());
    assert(post2_self_.mapping_1g() =~= pre_self_.mapping_1g());
    assert(post1_self_.mapping_1g() =~= post2_self_.mapping_1g());
    assert(post1_self_.mapping_1g@ =~= post2_self_.mapping_1g@);
    assert(post1_self_.mapping_1g@ == post2_self_.mapping_1g@);

    // kernel_entries: both pinned (extensional) to pre_self_.kernel_entries.
    assert(post1_self_.kernel_entries =~= pre_self_.kernel_entries);
    assert(post2_self_.kernel_entries =~= pre_self_.kernel_entries);
    assert(post1_self_.kernel_entries =~= post2_self_.kernel_entries);
    assert(post1_self_.kernel_entries == post2_self_.kernel_entries);
    assert(post1_self_.kernel_entries@ =~= post2_self_.kernel_entries@);
    assert(post1_self_.kernel_entries@ == post2_self_.kernel_entries@);

    // wf() on both runs — kept for trigger priming of derived spec fns.
    assert(post1_self_.wf());
    assert(post2_self_.wf());
}
